CREATE TABLE IF NOT EXISTS events_outbox (
  outbox_id bigserial PRIMARY KEY,
  event_id text,
  target text NOT NULL DEFAULT 'discord',
  action text NOT NULL DEFAULT 'notify',
  idempotency_key text,
  payload jsonb NOT NULL DEFAULT '{}'::jsonb,
  status text NOT NULL DEFAULT 'pending',
  retry_count integer NOT NULL DEFAULT 0,
  scheduled_at timestamptz NOT NULL DEFAULT NOW(),
  sent_at timestamptz,
  last_error text,
  created_at timestamptz NOT NULL DEFAULT NOW()
);
ALTER TABLE events_outbox ADD COLUMN IF NOT EXISTS status text NOT NULL DEFAULT 'pending';
ALTER TABLE events_outbox ADD COLUMN IF NOT EXISTS scheduled_at timestamptz NOT NULL DEFAULT NOW();
ALTER TABLE events_outbox ADD COLUMN IF NOT EXISTS last_error text;
WITH dead_all AS (SELECT * FROM events_outbox WHERE status = 'dead'), dead_sample AS (SELECT outbox_id, event_id, action, target, last_error FROM dead_all ORDER BY scheduled_at DESC LIMIT 5) SELECT COALESCE((SELECT COUNT(*)::int FROM dead_all), 0) AS dead_count, COALESCE(json_agg(dead_sample), '[]'::json) AS dead_samples FROM dead_sample;

