const count = Number($json.dead_count || 0);
const samples = Array.isArray($json.dead_samples) ? $json.dead_samples : [];
const lines = [];
lines.push('[PetSafe/Outbox] DLQ detected');
lines.push('Dead count: ' + count);
if (samples.length) {
  lines.push('Samples:');
  samples.forEach((item) => {
    const row = [item.outbox_id, item.event_id, item.target, item.action].filter(Boolean).join(' | ');
    lines.push('- ' + row);
  });
}
const content = lines.join('\n').slice(0, 1900);
return [{ json: { content } }];
